1	/**
2	 * Dashboard API server — serves signal/trade/settings data to the React frontend.
3	 * Runs on port 3200.
4	 */
5	import express from 'express';
6	import cors from 'cors';
7	import path from 'path';
8	import fs from 'fs';
9	import dotenv from 'dotenv';
10	
11	dotenv.config({ path: path.join(__dirname, '..', '.env') });
12	
13	import { getKalshiClient } from './kalshi-auth';
14	import { getRecentSignals } from './db';
15	import { getRecentArbSignals, scanArbOpportunities } from './arb/scanner';
16	import { printPaperSummary, settlePaperTrades, getDailyPnL, DAILY_LOSS_LIMIT, computeBrierStats } from './paper';
17	import { scanAll } from './signals';
18	
19	const app = express();
20	app.use(cors());
21	app.use(express.json());
22	
23	const DATA_DIR = path.join(__dirname, '..', 'data');
24	const PAPER_FILE = path.join(DATA_DIR, 'paper-trades.json');
25	const SCANS_FILE = path.join(DATA_DIR, 'scans.json');
26	const SETTINGS_FILE = path.join(DATA_DIR, 'settings.json');
27	
28	function readJson(file: string, def: unknown) {
29	  try { if (fs.existsSync(file)) return JSON.parse(fs.readFileSync(file, 'utf8')); } catch {}
30	  return def;
31	}
32	
33	function writeJson(file: string, data: unknown) {
34	  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
35	  fs.writeFileSync(file, JSON.stringify(data, null, 2));
36	}
37	
38	// ── Portfolio ────────────────────────────────────────────────────────────────
39	app.get('/api/portfolio', async (_req, res) => {
40	  const client = getKalshiClient();
41	  if (!client) return res.json({ balance: null, positions: [], error: 'No API credentials' });
42	  const [balance, positions] = await Promise.all([client.getBalance(), client.getPositions()]);
43	  res.json({ balance, positions });
44	});
45	
46	// ── Signals ──────────────────────────────────────────────────────────────────
47	app.get('/api/signals', (_req, res) => {
48	  const signals = getRecentSignals(50);
49	  res.json(signals);
50	});
51	
52	// ── Paper trades ─────────────────────────────────────────────────────────────
53	app.get('/api/paper', (_req, res) => {
54	  const trades = readJson(PAPER_FILE, []) as unknown[];
55	  res.json(trades);
56	});
57	
58	app.post('/api/paper/settle', async (_req, res) => {
59	  await settlePaperTrades();
60	  const trades = readJson(PAPER_FILE, []) as unknown[];
61	  res.json({ ok: true, trades });
62	});
63	
64	// ── Brier score calibration ──────────────────────────────────────────────────
65	app.get('/api/brier', (_req, res) => {
66	  const stats = computeBrierStats();
67	  res.json(stats || { error: 'No calibrated trades yet' });
68	});
69	
70	// ── Scan history ─────────────────────────────────────────────────────────────
71	app.get('/api/scans', (_req, res) => {
72	  const scans = readJson(SCANS_FILE, []) as unknown[];
73	  res.json(scans.slice(-100).reverse());
74	});
75	
76	// ── Manual scan trigger ───────────────────────────────────────────────────────
77	app.post('/api/scan', async (_req, res) => {
78	  try {
79	    const results = await scanAll();
80	    res.json({ ok: true, results });
81	  } catch (err) {
82	    res.status(500).json({ error: err instanceof Error ? err.message : 'Scan failed' });
83	  }
84	});
85	
86	// ── Settings ──────────────────────────────────────────────────────────────────
87	app.get('/api/settings', (_req, res) => {
88	  const defaults = {
89	    tradingMode: process.env.TRADING_MODE || 'paper',
90	    maxTradeDollars: parseInt(process.env.MAX_TRADE_DOLLARS || '25'),
91	    minEdgeDegrees: parseInt(process.env.MIN_EDGE_DEGREES || '3'),
92	    cities: ['NYC', 'CHI', 'MIA', 'DAL', 'ATL', 'NOLA'],
93	    verticals: [
94	      { id: 'weather', name: 'Weather', active: true, description: 'Daily high/low temperature markets' },
95	      { id: 'economics', name: 'Economics', active: false, description: 'CPI, Fed rate, jobs data' },
96	      { id: 'sports', name: 'Sports', active: false, description: 'Game outcomes, player stats' },
